sql:
SELECT injury_description
FROM player_injuries
WHERE player_id = 1022870;

external_knowledge:
- "standout players" refers to players who have a total score greater than 50;
- "team that's been doing pretty well" refers to team ID 10;
- "combined performance scores" refers to the sum of all scores for a player;
- "notable threshold" is set at 50 points.

sql:
SELECT player_id, player_class
FROM player_teams
WHERE team_id = (SELECT team_id FROM teams WHERE team_name = 'Team A');

SELECT position, COUNT(player_id) AS player_count
FROM player_teams
GROUP BY position;

SELECT team_name 
FROM teams
WHERE team_id IN (
  SELECT team_id 
  FROM player_teams
  WHERE player_id IN (
    SELECT player_id 
    FROM player_injuries
  )
);

SELECT DISTINCT t.team_id, t.stadium_name
FROM teams t
JOIN player_teams pt ON t.team_id = pt.team_id;

SELECT player_class, position, join_date, leave_date
FROM player_teams
WHERE player_id = 1022870;

SELECT COUNT(DISTINCT player_id) AS TotalPlayers
FROM game_stats
WHERE score > 100;

SELECT DISTINCT games.opponent_id 
FROM games 
WHERE games.team_id = 1;

SELECT teams.team_name, player_teams.player_id
FROM teams
INNER JOIN player_teams ON teams.team_id = player_teams.team_id;
